import moment from "moment"
let companyList = [];
let company = null;
let companyjs = null;
let reportList = [];
let reportDefault= [   
    { CODE: '20', NAME: '20 - WORKING DETAIL', REPORT_PATH: 'report/10/21/woosung/1021052_working_detail_woosung.xlsx'},

];
let reportCompany = [];
let _1021052_woosung = {
    getReportList: async(that) =>{
        await prepareCommonData(that);
        let reports = [];

        reports = [...reportDefault, ...reportCompany];
        reportList = [...reports];
		reportList = reportList.sort((a, b) => (Number(a.CODE) > Number(b.CODE)) ? 1 : -1)
        return reportList;
    }, 
    print: async(that, selectedReport) => {
        that.isInProcessing = true;
        that.processStatus = that.$t("making_report");
        let reportInfo = reportList.find(x => x.CODE === selectedReport);

        try {
            if( reportDefault.findIndex( q=> q.CODE == selectedReport)  >=0  && Number(selectedReport) < 30 ) { //report default
                switch(selectedReport) {
                    case "20": {
                        await printWorkingDetail( that, reportInfo)
                        break;
                    }
                }
            } else { // report cho cty
                await companyjs.print(that, selectedReport);
            }
            
        } catch(e) {
            console.log(e)
            that.processStatus = that.$t("fail_to_export_report");
        } finally {
            that.isInProcessing = false;
        }
    },

}


let prepareCommonData = async (that) => {
    companyList = await that._getCompany();
    company = companyList.find(x => x["PK"] === that.selectedCompany );
};

let printWorkingDetail = async( that, reportInfo) => {
    let selectedPeriod = that.salPeriodList.find(q => q.CODE == that.selectedPeriod);
    let p_param = [that.selectedOrg, that.selectedWg, that.selectedNation, selectedPeriod.CODE, selectedPeriod.TIMES, that.selectedMonth, that.selectedEmpPK, that.selectedStatus];
    let p_param_days = [that.selectedCompany, selectedPeriod.ACTIVE_FROM_DT, selectedPeriod.ACTIVE_TO_DT]
    let startColDate = 6;
    let headerRow = 5;
    let startDate = moment(String(selectedPeriod.ACTIVE_FROM_DT), "YYYYMMDD");
    let endDate = (moment(String(selectedPeriod.ACTIVE_TO_DT), "YYYYMMDD")).add(1, 'days');
    let idx = 0;
    let i=1;
    let hiddenCols = [];  
    let reportHeader = {};


    //header: update column name
    for (let d = startDate; d.isBefore(endDate); d.add(1, 'days')) {
        reportHeader["A"+ i] = d.format("D");
        ++i;
    }
    //header : hide columns
    for (let j = i-1; j < 31; j++) {
        hiddenCols.push(j + startColDate);
    }

    let exceljs =  require("@/plugins/exceljs.js");
    if(!!exceljs) {
        exceljs = exceljs.default;
    }

    await exceljs.createWorkbook(that, reportInfo.REPORT_PATH);
    let worksheet = exceljs.worksheet();

    
    const dsoComp = {  type: 'grid',  selpro: 'HR_RPT_1020050_COMPANY_INFO', para: [that.selectedOrg, that.selectedMonth]  };
    const dsoDayType =  { type: 'grid', selpro: 'HR_RPT_1020050_GET_DAY_TYPE', para:  p_param_days };
    const dsoData = {  type: 'grid',  selpro: 'HR_RPT_1021052_WORKDETAIL_WS', para: p_param };
    let dataComp = await that._dsoCall(dsoComp, 'select', false);
    let dayTypes = await that._dsoCall(dsoDayType, 'select', false);
    let datas = await that._dsoCall(dsoData, 'select', false);
    if(datas && datas.length <= 0)  {
        that.showNotification("warning", that.$t("no_data_found"), "", 4000);
        return;
    }
    let startRow = 7;
    let startRow2 = 7;
    let rowOfRange = 3;
    let totalRow = startRow + (datas.length*3) ;
    let totalData = {TOTAL_TEXT: "TOTAL(H)"};
    let keys = Object.keys(datas[0]);
    keys.forEach(key => {
    let vals = datas.map( q =>  (  isNaN(q[key]) ||  q[key]== null  ) ? 0 :  q[key]  );
    let sumVal = Math.round(that._Total(vals)*100)/100;
    totalData[key] = sumVal  ? sumVal : null ;
    })
    datas.unshift({});
    exceljs.insertRange(that, "A5:AZ6", reportHeader);
    exceljs.insertRange(that, "A1:AY3", dataComp[0]);
    exceljs.insertRange2(that, "A7:AZ9", datas);
    exceljs.setHideColumns(that, hiddenCols, true); // hiden cột 
    datas.shift();
    worksheet.spliceRows(startRow, rowOfRange); 
    
    let imageBase64 = "data:image/png;base64,";

    let id = exceljs.insertImageBase64(that, imageBase64);
	let sheet = exceljs.worksheet();
	// console.log("id", id)
	sheet.addImage(id, {
		tl:{col: 22, row: totalRow + 4 },
		br:{col: 44 , row: totalRow + 14 }
	});

    for(let i =0; i< datas.length; i++) {
        //date info
        let startDate = moment(String(selectedPeriod.ACTIVE_FROM_DT), "YYYYMMDD");
        let endDate = (moment(String(selectedPeriod.ACTIVE_TO_DT), "YYYYMMDD")).add(1, 'days');
        worksheet.mergeCells(startRow2,3 ,startRow2 + 1,3) ;
        idx = 0;

        for (let d = startDate; d.isBefore(endDate); d.add(1, 'days')) {
            if(i == 0) exceljs.getCellByIndex(that, headerRow, startColDate + idx).value = d.format("DD");
            
            let day  = dayTypes.find( q=> q["CAR_DATE"] == d.format("YYYYMMDD") );
            
            let cell1 = exceljs.getCellByIndex(that, startRow + (rowOfRange*i)    , startColDate + idx);
            let cell2 = exceljs.getCellByIndex(that, startRow + (rowOfRange*i) + 1 , startColDate + idx);
            let cell3 = exceljs.getCellByIndex(that, startRow + (rowOfRange*i) + 2 , startColDate + idx);
            
            if(day && (day.HOL_TYPE == "SUN" || day.HOL_TYPE == "HOL")) {
                cell1.fill = { 
                    type: 'pattern',  pattern:'solid'
                    , fgColor:{ argb: day.HOL_TYPE == "SUN" ? 'BBBBBB' :  (day.HOL_TYPE == "HOL" ? "ffffff" : null) }
                    , bgColor:{ argb: day.HOL_TYPE == "SUN" ? 'BBBBBB' :  (day.HOL_TYPE == "HOL" ? "ffffff" : null)} 
                };
                cell2.fill = { 
                    type: 'pattern',  pattern:'solid'
                    , fgColor:{ argb: day.HOL_TYPE == "SUN" ? 'BBBBBB' :  (day.HOL_TYPE == "HOL" ? "ffffff" : null) }
                    , bgColor:{ argb: day.HOL_TYPE == "SUN" ? 'BBBBBB' :  (day.HOL_TYPE == "HOL" ? "ffffff" : null)} 
                };
                cell3.fill = { 
                    type: 'pattern',  pattern:'solid'
                    , fgColor:{ argb: day.HOL_TYPE == "SUN" ? 'BBBBBB' :  (day.HOL_TYPE == "HOL" ? "ffffff" : null) }
                    , bgColor:{ argb: day.HOL_TYPE == "SUN" ? 'BBBBBB' :  (day.HOL_TYPE == "HOL" ? "ffffff" : null)} 
                };
            }
            idx++;
            
        }
        startRow2= startRow2 + 3;
    } 
    
    // exceljs.insertRows(that,startRow, datas);
    exceljs.insertRowData(that, totalRow, totalData);

   
    
    await exceljs.dowloadWorkbook(that,  `${reportInfo.NAME}.xlsx`);
    that.processStatus = that.$t("complete");


};

export default _1021052_woosung;